using System.Collections;
using System.Collections.Generic;
using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int playerHealth = 100;
    public int currency = 0;
    public float damageMultiplier = 1f;

    private void Update()
    {
        if (playerHealth <= 0)
        {
            // Game Over logic here
        }
    }

    public void TakeDamage(float amount)
    {
        playerHealth -= Mathf.RoundToInt(amount * damageMultiplier);
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
    }

    public int GetPlayerHealth()
    {
        return playerHealth;
    }

    public int GetCurrency()
    {
        return currency;
    }
}

public class ShopController : MonoBehaviour
{
    public PlayerStats playerStats;

    public Dictionary<string, int> shopItems = new Dictionary<string, int>()
    {
        {"Health Potion", 10},
        {"Damage Boost", 20}
    };

    public void BuyItem(string itemName)
    {
        if (playerStats.currency >= shopItems[itemName])
        {
            playerStats.AddCurrency(-shopItems[itemName]);
            // Apply item effect here
        }
    }

    public int CalculatePrice(int amount)
    {
        return Mathf.RoundToInt(amount * 10);
    }
}